import puppeteer from "puppeteer-core";
import { fileURLToPath } from "url";
import path from "path";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const SRC = path.join(__dirname, "转正答辩_v3_动画版.html");
const OUT = path.join(__dirname, "转正答辩_v3.pdf");

const SLIDE_W = 1280;
const SLIDE_H = 720;

const browser = await puppeteer.launch({
  executablePath: "C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe",
  headless: true,
  args: [`--window-size=${SLIDE_W},${SLIDE_H}`],
});

const page = await browser.newPage();
await page.setViewport({ width: SLIDE_W, height: SLIDE_H });

await page.goto(`file:///${SRC.replace(/\\/g, "/")}`, {
  waitUntil: "networkidle0",
  timeout: 30000,
});

await page.addStyleTag({
  content: `
    /* PDF 打印样式：隐藏工具栏、背景灰色，每页一张幻灯片 */
    .deck-toolbar { display: none !important; }
    html, body {
      background: #fff !important;
      margin: 0 !important;
      padding: 0 !important;
    }
    .deck-wrap {
      gap: 0 !important;
      padding: 0 !important;
    }
    .deck-slide {
      box-shadow: none !important;
      border-radius: 0 !important;
      page-break-after: always;
      break-after: page;
      margin: 0 !important;
    }
    .deck-slide:last-child {
      page-break-after: auto;
      break-after: auto;
    }
    @media (max-width: 1360px) {
      .deck-slide {
        transform: none !important;
        margin-bottom: 0 !important;
      }
    }
  `,
});

await page.pdf({
  path: OUT,
  width: `${SLIDE_W}px`,
  height: `${SLIDE_H}px`,
  printBackground: true,
  margin: { top: 0, right: 0, bottom: 0, left: 0 },
  preferCSSPageSize: false,
});

await browser.close();
console.log(`PDF saved → ${OUT}`);

